import java.util.*;

public class FractionalKnapsack {

    public double maxValue(int[] weights, int[] values, int capacity) {
        int n = weights.length;
        // Create items array and sort by value/weight ratio descending
        Integer[] idx = new Integer[n];
        for (int i = 0; i < n; i++) idx[i] = i;
        Arrays.sort(idx, (a, b) -> Double.compare(
            (double) values[b] / weights[b],
            (double) values[a] / weights[a]
        ));

        double totalValue = 0;
        int remaining = capacity;

        for (int i : idx) {
            if (remaining <= 0) break;
            if (weights[i] <= remaining) {
                // TODO: take entire item: totalValue += values[i]; remaining -= weights[i];
            } else {
                // TODO: take fraction: totalValue += values[i] * ((double) remaining / weights[i]); remaining = 0;
            }
        }
        return totalValue;
    }

    public static void main(String[] args) {
        FractionalKnapsack fk = new FractionalKnapsack();
        int[] w = {10, 20, 30};
        int[] v = {60, 100, 120};
        System.out.printf("Max value (cap=50): %.2f%n", fk.maxValue(w, v, 50));

        int[] w2 = {2, 3, 5, 7};
        int[] v2 = {10, 5, 15, 7};
        System.out.printf("Max value (cap=10): %.2f%n", fk.maxValue(w2, v2, 10));
    }
}

import java.util.*;

public class TaskLateness {

    static class Task {
        String name; int proc, deadline;
        Task(String n, int p, int d){name=n;proc=p;deadline=d;}
    }

    public int minMaxLateness(List<Task> tasks) {
        // TODO: Sort tasks by deadline (earliest first)
        // Process in order, tracking current time and max lateness
        int time = 0, maxLate = 0;
        for (Task t : tasks) {
            time += t.proc;
            int lateness = Math.max(0, time - t.deadline);
            maxLate = Math.max(maxLate, lateness);
            System.out.printf("  Task %s: finish=%d deadline=%d lateness=%d%n",
                              t.name, time, t.deadline, lateness);
        }
        return maxLate;
    }

    public static void main(String[] args) {
        TaskLateness tl = new TaskLateness();
        List<Task> tasks = new ArrayList<>(Arrays.asList(
            new Task("A", 3, 6),
            new Task("B", 2, 4),
            new Task("C", 1, 3)
        ));
        System.out.println("--- Greedy (earliest deadline first) ---");
        int maxLate = tl.minMaxLateness(tasks);
        System.out.println("Max lateness: " + maxLate);
    }
}

